INSERT OR IGNORE INTO posts (id, bbsid, board_id, user_id, title, content, content_text, signature, posted_at, reply_count, source_file, wayback_ts) VALUES (2226, 213296, 13, 19, '夜半起床看月亮', '����夜晚归家，7蹭8蹭已是亥时过半。倚着靠背椅，迷糊中--脑子里似乎还残留着整点电视新闻报道的碎片。但感觉中---下眼皮似乎正奋起粉碎上眼皮舆图肉体相亲的狼子野心。无奈新闻频道一个有关恐怖分子的报道甚是精彩。于是古人悬梁刺股，我便狠掐自咯~~~痛！找回初中横跨3.8线被隔壁女生自卫反击的感觉了。节目刚完，习惯换了个频道，U一个关于9.11的系列报道！于是，我U有滋有味的看了一小会。醒来时，隔壁比我还夜猫子的柳老师屋内已是偃旗息鼓了。伸伸懒腰，吸口气。想来柳老师缸里为数不多的几头鱼也似我如释重负。不同的是，我陪周公耍了段太极精神倍佳，鱼却大口喘气不必与人折腾了。
<br>
<br>����洗梳一番，已是凌晨两点过半。打开窗台上的纱窗，睡意就也全无------月色虽被栏杆上的雨披完全挡去，但月光如流水，正缓缓的泻入我房来。
<br>
<br>����我赶紧给猪头发条短信--起床看月亮，N久过后不见回复。想必此刻猪头已是zzzzzZ着好梦。一直以来我总是怀疑猪头国宝般的眼圈是天赋异禀，可她却总辩解此乃周公有意噩梦相戏所致。直到有回上她们家给电脑换硬盘，我这螺丝、机箱叮当锁得勤快，开口再要一工具却不见她有反应。抬头一望，她已如Zoo里晒秋日的Monkey，肢体舒坦得自在。打此我明白一个道理“有时天赋异禀是得用借口掩饰地”。打着赤膊，我就这么靠着6楼窗台的栏杆。由于刚下完一阵暴雨，此刻抬头望去，诗里‘月明星稀’的景致端端正正映入我的眼帘。“举头望明月，低头思故乡”，不由想起李白这句小儿也能信口背来的诗句。可恶的猪头啊，人在异地，明月当空，可她竟有如此zzzzZ的闲情？暂且不去理她。
<br>
<br>����月，似乎总能让诗人胸涌澎湃。不由又忆起另一句“月是故乡明”，明了5字却是概括了太白朗朗上口10字的游子心情。“举杯邀明月，对影成三人”又是另外一种境界。古来诗里能出现月亮最多的，恐怕也就李太白一人了。盛世之下，即便无人对饮，无人对吟。一壶酒、一个月亮、眼前花花草草，哪怕是明月下投映出的影子。也能吟诵出令人热血亢奋的句子。想必入此境界，李白也就TM不把唐明皇当那么回事了。让高力仕脱靴、倒酒、磨墨那自是不在话下。当然，酒醒之后该让人嫉恨还得让人嫉恨，该受罪太白爷爷也认了。但若按秦朝律法追究元凶。除了这酒精醉该万S外，恐怕月亮也得跟着连坐了。
<br>
<br>����这世道，除了张宇深情款款的痛恨月亮惹祸外，恐怕就就剩下后弈和孙悟空痛恨月亮了，尤其是满月。后羿那谗嘴的老婆就是在满月下贪吃了狠心王母给的长生不老之药。不吃不要紧，一吃就抛夫而去，直飞9宵云宫。还好月亮也仅只有一个，轩辕弓、箭都已被上天收回。后羿没有了射月亮的借口和工具。恕我如此大胆猜想，这赏月亮吃月饼就是后羿发明的。目的就是这时候发泄发泄月亮的夺妻之恨。：）-----‘射不下来！就把你做成饼吃掉’。赏月看似雅致，其实那不过是后羿一把鼻涕一把泪的盼这么个中秋嫦娥露个脸，好说说夫妻心里事。还好嫦娥尚守妇道，虽有壮汉吴刚伐木于门外，却未做出对不住后羿的红杏出墙之事。即便是天篷元帅爱慕之久，醉酒寻胆表白。也被她一道懿旨告发到玉皇大帝处。投个猪头人身，发配给唐朝和尚当了个保镖。当然，这都是后话了。
<br>
<br>����至于孙悟空为啥会痛恨月亮呢？因为孙悟空是纳米克星人。月圆的时候就会变成发狂的大猩猩。一不小心，就把保护龙珠的爷爷孙悟饭给踩死了。还好后来悟空的尾巴给去掉，即便月亮再怎么圆，也不再发狂伤人了。------鸟山明笔下的《7龙珠》。前半部故事天马行空的令人叫绝！
<br>
<br>����言归正传，唐朝诗人除了盛唐时期的李太白放荡不羁外，还有一群诗人以诗风豪放粗旷为后人所传吟，那便是边塞诗人。王松龄的“秦时明月汉时关”又是有别于李白放荡的另种境界----如果说李白的诗是一副棋局中笑傲江湖吃遍大小的一匹傲马。那么边塞私人的诗就是阔棋盘场上大兵出塞，血战沙场，马革裹尸，雄大恢宏的悲壮场面。但秦时的明月却是厌恶连连征战的子民心态。挺豪气的一个月亮和雄关引来的却是一句“万里长征人未还”的悲凉感慨。但使龙城飞将在，不教胡马渡阴山。一种如何形容的壮志豪情啊！！
<br>
<br>����唐诗宋词，刚谈完李白就不由让人想起宋代的苏轼了。因为二者诗、词都以豪迈不羁著称。水调歌头（明月几时有）“明月几时有，把酒问青天，不知天上宫阙，今夕是何年。。。。。。但愿人长久，千里共婵娟”。看完词评，说这词虽然开篇破空而出，雄起突兀。下篇浑朴苍凉。算是旷达一类。不由一乐，因为初读此词时感觉苏轼眼里有除了明月、美酒、最后就剩嫦娥了。苏轼的词要嘛豪放极致，要嘛婉约至凄凉。江城子（正月二十日夜记梦）到大凄凉。相传苏轼中年时花心纳妾，也挺疼小妾的。但从此词中不由还是读出苏轼对原配往昔深情的怀念，即便生死隔绝，人鬼殊途。“十年生死两茫茫，不思量，自难忘。千里孤坟，无处话凄凉。纵使相逢应不识，尘满面，鬓如霜。 夜来幽梦忽还乡，小轩窗，正梳妆。相顾无言，惟有泪千行。料得年年肠断处，明月夜，短松冈。”读到‘料得年年肠断处’词人之凄悲已是如鱼刺梗于喉咙。读罢‘明月夜，短松冈’却U是在未拔出这根刺的情况下咽下了一大口的菜跟饭。实虚结合，情真意切，哀惋欲绝，可谓中国古代较早版的人鬼情未了。
<br>
<br>����信马回缰，雨后的清风似一无形的手，拂过身体，扬上发梢。不经意间，风也顺道捎来了远处草丛里虫豸的浅声低吟。月亮出来了，从我刚被雨披掩着的视线。散着柔柔软软奶白色的光。我悄悄燃起一根烟，月光如流水般，依稀就见着烟雾如袅娜的舞女，缓缓的扭动着腰肢，腾空，继而弥散于夜色之中。一阵微风不期而至。闭上眼睛，脑海不由浮现出王维的《山居秋冥》“空山新雨后，天气晚来秋。明月松间照，清泉石上流。。。。。。”我已然成了这月色中的国王。
<br>    
<br>����愿天下诸君“海上升明月，天涯共此时。”
<br>
<br>
<br>                                                                                                                
<br>
<br>                                             平方3天马行空于
